from hypothesis import given, integers

# Property: adding zero doesn't change value
@given(integers())
def test_add_zero(x):
    assert x + 0 == x

# Property: sorting is stable
@given(integers().filter(lambda x: x > 0))
def test_sort_stability(items):
    original = items[:]
    sorted_once = sorted(original)
    sorted_twice = sorted(sorted_once)
    assert sorted_once == sorted_twice
